// Handles all T test cases
#include <stdio.h>
#include <stdlib.h>

void primeFactorization(int *numbers, int n) {
    if (n <= 0) return;

    int maxVal = 0;
    for (int i = 0; i < n; ++i) if (numbers[i] > maxVal) maxVal = numbers[i];
    if (maxVal < 2) maxVal = 2;

    // allocate SPF array of size maxVal+1
    int *spf = (int*)malloc((maxVal + 1) * sizeof(int));
    if (!spf) {
        // allocation failed
        return;
    }

    // initialize spf: spf[x] = x
    spf[0] = 0;
    spf[1] = 1;
    for (int i = 2; i <= maxVal; i++) spf[i] = i;

    // sieve to fill smallest prime factors
    for (long long i = 2; i * i <= maxVal; ++i) {
        if (spf[i] == i) {
            for (long long j = i * i; j <= maxVal; j += i) {
                if (spf[j] == j) spf[j] = (int)i;
            }
        }
    }

    // factorize each number using spf
    for (int i = 0; i < n; ++i) {
        int num = numbers[i];
        // As per constraints num >= 2, but handle safely
        if (num <= 1) {
            printf("\n");
            continue;
        }

        int firstPrinted = 0;
        while (num > 1) {
            int p = spf[num];
            // print all p's
            while (num % p == 0) {
                if (firstPrinted) printf(" ");
                printf("%d", p);
                firstPrinted = 1;
                num /= p;
            }
        }
        printf("\n");
    }

    free(spf);
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        int *numbers = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &numbers[i]);
        }
        primeFactorization(numbers, n);
        free(numbers);
    }
    return 0;
}

