#include <iostream>
#include <vector>
using namespace std;

class Solution {
public:
    vector<vector<int>> primeFactorization(vector<int> &numbers) {
        int maxN = 200000; // since numbers[i] <= 2*10^5
        vector<int> spf(maxN + 1);

        // Precompute smallest prime factor for every number
        for (int i = 2; i <= maxN; i++) {
            spf[i] = (i % 2 == 0 ? 2 : i);
        }

        for (long long i = 3; i * i <= maxN; i += 2) {
            if (spf[i] == i) {
                for (long long j = i * i; j <= maxN; j += i) {
                    if (spf[j] == j) spf[j] = i;
                }
            }
        }

        vector<vector<int>> result;

        // Factorize each number using spf[]
        for (int num : numbers) {
            vector<int> factors;
            while (num > 1) {
                int p = spf[num];
                while (num % p == 0) {
                    factors.push_back(p);
                    num /= p;
                }
            }
            result.push_back(factors);
        }

        return result;
    }
};

int main() {
    int t;
    cin >> t;
    while (t--) {
        int n;
        cin >> n;
        vector<int> numbers(n);
        for (int i = 0; i < n; i++) {
            cin >> numbers[i];
        }
        Solution solution;
        vector<vector<int>> result = solution.primeFactorization(numbers);
        for (const auto &factors : result) {
            for (int factor : factors) {
                cout << factor << " ";
            }
            cout << endl;
        }
    }
    return 0;
}

