let idx = 0;

function readLine() {
    return input[idx++];
}

function readInt() {
    return parseInt(readLine());
}

function readInts() {
    return readLine().split(' ').map(x => parseInt(x));
}

class Solution {
    primeFactorization(numbers) {
        const maxN = 200000; // since numbers[i] ≤ 2×10^5
        const spf = new Array(maxN + 1).fill(0);

        // Initialize SPF
        for (let i = 2; i <= maxN; i++) {
            if (i % 2 === 0) spf[i] = 2;
            else spf[i] = i;
        }

        // Compute SPF using sieve
        for (let i = 3; i * i <= maxN; i += 2) {
            if (spf[i] === i) {
                for (let j = i * i; j <= maxN; j += i) {
                    if (spf[j] === j) spf[j] = i;
                }
            }
        }

        let result = [];

        // Factorize each number
        for (let num of numbers) {
            let factors = [];
            while (num > 1) {
                let p = spf[num];
                // print all p's
                while (num % p === 0) {
                    factors.push(p);
                    num = Math.floor(num / p);
                }
            }
            result.push(factors);
        }

        return result;
    }
}

